Here are the public test cases for feature1_1_plugin_selection:
{
  "description": "Checks whether a requested routing provider can be created, reporting availability and a normalized unavailable-provider error when it cannot.",
  "cases": [
    {
      "input": {
        "plugin": "cse"
      },
      "expected_output": "plugin=cse\navailable=true\nerror=none\n"
    }
  ]
}

Here are the public test cases for feature1_2_rule_weight_validation:
{
  "description": "Validates that every routing rule for a destination has a total candidate weight no greater than the full traffic budget and reports each rule total.",
  "cases": [
    {
      "input": {
        "rules": {
          "service1": [
            {
              "route": [
                {
                  "weight": 50
                },
                {
                  "weight": 50
                }
              ]
            }
          ]
        }
      },
      "expected_output": "valid=true\nservice=service1 rule_index=0 total_weight=100\n"
    }
  ]
}

Here are the public test cases for feature2_request_route_selection:
{
  "description": "Selects destination metadata for an invocation by evaluating route rules for the requested destination, including header matches, default rules, zero-weight alternatives, and missing destinations.",
  "cases": [
    {
      "input": {
        "rules": {
          "RPCServer": [
            {
              "precedence": 2,
              "match": {
                "headers": {
                  "test": {
                    "exact": "user"
                  }
                }
              },
              "route": [
                {
                  "weight": 100,
                  "tags": {
                    "version": "v2"
                  }
                }
              ]
            },
            {
              "precedence": 1,
              "route": [
                {
                  "weight": 100,
                  "tags": {
                    "version": "v3"
                  }
                }
              ]
            }
          ]
        },
        "service": "RPCServer",
        "headers": {
          "cookie": "user=jason",
          "X-Age": "18",
          "test": "user"
        },
        "source": {
          "tags": {
            "version": "v2"
          }
        }
      },
      "expected_output": "service=RPCServer\nerror=none\nselected=true\nversion=v2\n"
    }
  ]
}

Here are the public test cases for feature3_request_match_conditions:
{
  "description": "Evaluates whether request context satisfies source identity, source tags, header operators, and referenced request policies.",
  "cases": [
    {
      "input": {
        "match": {
          "source": "service",
          "sourceTags": {
            "tag1": "v1"
          },
          "httpHeaders": {
            "cookie": {
              "regex": "((abc.)def.)ghi"
            },
            "age": {
              "greater": "10"
            }
          }
        },
        "headers": {
          "cookie": "abc-def-ghi",
          "age": "15"
        },
        "source": {
          "name": "service",
          "tags": {
            "app": "app",
            "version": "0.1",
            "tag1": "v1"
          }
        }
      },
      "expected_output": "matched=true\n"
    }
  ]
}

Here are the public test cases for feature4_weighted_distribution:
{
  "description": "Builds a weighted selection pool and reports the deterministic distribution of versions selected over a fixed number of picks, filling unused weight with a latest-version fallback.",
  "cases": [
    {
      "input": {
        "key": "test",
        "picks": 100,
        "routes": [
          {
            "weight": 25,
            "tags": {
              "version": "A"
            }
          },
          {
            "weight": 30,
            "tags": {
              "version": "B"
            }
          },
          {
            "weight": 40,
            "tags": {
              "version": "C"
            }
          }
        ]
      },
      "expected_output": "picks=100\nversion=A count=25\nversion=B count=30\nversion=C count=40\nversion=latest count=5\n"
    }
  ]
}

Here are the public test cases for feature5_dark_launch_translation:
{
  "description": "Translates high-level rollout rules into route rules with route tags, weights, precedence, and optional header match operators.",
  "cases": [
    {
      "input": {
        "rule": {
          "policyType": "RULE",
          "ruleItems": [
            {
              "groupName": "test",
              "groupCondition": "version=1.0",
              "policyCondition": "foo=bar",
              "versions": [
                "1.0"
              ]
            }
          ]
        }
      },
      "expected_output": "rules=1\nrule_index=0 precedence=1 routes=1\nroute_index=0 weight=100 version=1.0\nheader=Foo caseInsensitive=false\nheader=Foo exact=bar\n"
    }
  ]
}

Here are the public test cases for feature6_configuration_rule_loading:
{
  "description": "Loads route rules from an in-memory configuration source, then reflects create, update, and delete events in the fetched rule counts for named destinations.",
  "cases": [
    {
      "input": {
        "initial": {
          "servicecomb.darklaunch.policy.order": "{\"policyType\":\"RATE\",\"ruleItems\":[{\"groupName\":\"s0\"},{\"groupName\":\"s1\"}]}",
          "servicecomb.routeRule.web": "\n      - precedence: 1\n        route:\n        - tags:\n            version: 1.0\n            project: x\n          weight: 50\n        - tags:\n            version: 2.0\n            project: z\n          weight: 50\n"
        },
        "fetch": [
          "web",
          "order"
        ]
      },
      "expected_output": "service=web rules=1\nservice=order rules=1\n"
    }
  ]
}
